import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

import { addRow } from '../../crud/crud';
import { handleLogout } from '../../consts/handleLogout';

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddCrossroad() {
    const [type_crossroad_id, setTypeCrossroadID] = useState('');
    const [latitude, setLatitude] = useState('');
    const [longitude, setLongitude] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const submitCrossroad = async (e) => {
        const headers = {
            'Content-Type': 'multipart/form-data',
            'Accept': 'application/json'
        }
        const crossroad = { type_crossroad_id, latitude, longitude };

        e.preventDefault();
        addRow('/crossroads/type_crossroads', crossroad, headers);
        setTypeCrossroadID('');
        setLatitude('');
        setLongitude('');
        navigate('/crossroads');
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">Дорожное хозяйство</Link>
                    <div class="btn-group">
                        <button type="button" class="btn btn-info">Пользователь</button>
                        <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                            <span class="visually-hidden">Переключатель выпадающего списка</span>
                        </button>
                        <ul class="dropdown-menu">
                            <li>
                                <a class="dropdown-item">
                                    <button
                                        onClick={() => { handleLogout(); navigate('/login') }}
                                        className='dropdown-item'
                                        disabled={loading}
                                    >
                                        {loading ? (
                                            <>
                                                <span className='spinner'></span>
                                                Выход...
                                            </>
                                        ) : 'Выйти'}
                                    </button>
                                </a>
                            </li>
                        </ul>
                    </div>
                </div>
            </nav>
            <form className='container' onSubmit={submitCrossroad}>
                <h1>Создание перекрестка.</h1>
                <div className='mb-3'>
                    <lable className='form-label'>ID типа перекрестка</lable>
                    <input 
                        type='text'
                        name='type_crossroad_id' 
                        value={type_crossroad_id.type_crossroad_id} 
                        onChange={(e) => setTypeCrossroadID(e.target.value)}
                        className='form-input'  
                        placeholder='ID типа перекрестка'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Широта</lable>
                    <input 
                        type='text'
                        name='latitude' 
                        value={latitude.latitude} 
                        onChange={(e) => setLatitude(e.target.value)}
                        className='form-input'  
                        placeholder='Широта'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Долгота</lable>
                    <input 
                        type='text'
                        name='longitude' 
                        value={longitude.longitude} 
                        onChange={(e) => setLongitude(e.target.value)}
                        className='form-input'  
                        placeholder='Долгота'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Добавить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/crossroads')}
                >
                    Назад
                </button>
            </form>
        </div>
    )

};

export default AddCrossroad;
